// 1. REACH BACK: Get every row from your initial Google Sheets node
// Use the exact name of your node here (case sensitive)
const existingRows = $("Fetch Existing Deals (Sheet)").all();

// 2. MAP: Create a simple list of just the links we already have
const processedLinks = existingRows.map(row => row.json.Link);

// 3. FILTER: Compare the current 70 RSS items against that list
return $input.all().filter(item => {
  // We only keep it if the link is NOT found in processedLinks
  return !processedLinks.includes(item.json.link);
});

const text = $json.text || "";
const match = text.match(/\{[\s\S]*\}/);
if (!match) return { json: { Score: 0, Reason: "No response" }};
const data = JSON.parse(match[0]);
return { json: data };
